PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE providers (
  provider_id TEXT PRIMARY KEY,
  provider_kind TEXT NOT NULL,
  provider_label TEXT NOT NULL,
  node_class TEXT,
  supports_water_quality INTEGER NOT NULL DEFAULT 0,
  supports_flow_monitoring INTEGER NOT NULL DEFAULT 0,
  supports_edge_vision_summary INTEGER NOT NULL DEFAULT 0,
  schema_version TEXT NOT NULL DEFAULT 'v1',
  write_token_hash TEXT NOT NULL,
  registered_at TEXT NOT NULL,
  last_seen_at TEXT NOT NULL
);
CREATE TABLE observations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  provider_id TEXT NOT NULL,
  pond_id TEXT NOT NULL,
  measurement_time TEXT NOT NULL,
  payload_json TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE TABLE events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  provider_id TEXT NOT NULL,
  pond_id TEXT NOT NULL,
  event_time TEXT NOT NULL,
  event_type TEXT NOT NULL,
  payload_json TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE TABLE recommendations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  provider_id TEXT NOT NULL,
  pond_id TEXT NOT NULL,
  analysis_time TEXT NOT NULL,
  payload_json TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE TABLE telegram_issue_throttle (
  throttle_key TEXT PRIMARY KEY,
  last_accepted_at TEXT NOT NULL,
  last_message_id TEXT,
  last_update_id TEXT,
  message_count INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE telegram_chat_messages (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  chat_key TEXT NOT NULL,
  chat_id TEXT,
  user_id TEXT,
  role TEXT NOT NULL,
  intent TEXT NOT NULL,
  message_text TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE TABLE telegram_chat_limits (
  limit_key TEXT PRIMARY KEY,
  bucket_name TEXT NOT NULL,
  window_started_at TEXT NOT NULL,
  request_count INTEGER NOT NULL DEFAULT 0,
  last_request_at TEXT NOT NULL
);
CREATE TABLE telegram_issue_moderation_audit (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  chat_id TEXT,
  user_id TEXT,
  message_id TEXT,
  issue_kind TEXT,
  original_text TEXT NOT NULL,
  decision TEXT NOT NULL,
  reason_code TEXT NOT NULL,
  reason_text TEXT NOT NULL,
  provider_name TEXT,
  model_name TEXT,
  created_at TEXT NOT NULL
);
CREATE TABLE recycled_devices (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    model TEXT UNIQUE NOT NULL,
    brand TEXT,
    description TEXT,
    teardown_url TEXT,
    created_at TEXT NOT NULL
, device_category TEXT, source_url TEXT, donor_rank REAL);
CREATE TABLE recycled_parts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    device_id INTEGER NOT NULL,
    part_name TEXT NOT NULL,
    species TEXT, 
    value TEXT, 
    designator TEXT, 
    description TEXT,
    created_at TEXT NOT NULL, genus TEXT, mounting TEXT, keywords TEXT, kicad_symbol TEXT, kicad_footprint TEXT, datasheet_url TEXT, quantity INTEGER, source_url TEXT, confidence REAL,
    FOREIGN KEY (device_id) REFERENCES recycled_devices(id) ON DELETE CASCADE
);
CREATE TABLE recycled_device_aliases (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    device_id INTEGER NOT NULL,
    alias TEXT NOT NULL,
    alias_type TEXT NOT NULL DEFAULT 'device_alias',
    source TEXT,
    created_at TEXT NOT NULL,
    UNIQUE (device_id, alias, alias_type),
    FOREIGN KEY (device_id) REFERENCES recycled_devices(id) ON DELETE CASCADE
);
CREATE TABLE recycled_part_aliases (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    part_id INTEGER NOT NULL,
    alias TEXT NOT NULL,
    alias_type TEXT NOT NULL DEFAULT 'part_alias',
    source TEXT,
    created_at TEXT NOT NULL,
    UNIQUE (part_id, alias, alias_type),
    FOREIGN KEY (part_id) REFERENCES recycled_parts(id) ON DELETE CASCADE
);
CREATE TABLE recycled_device_evidence (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    device_id INTEGER NOT NULL,
    part_id INTEGER,
    source_type TEXT NOT NULL,
    source_url TEXT,
    excerpt TEXT,
    confidence REAL,
    created_at TEXT NOT NULL,
    FOREIGN KEY (device_id) REFERENCES recycled_devices(id) ON DELETE CASCADE,
    FOREIGN KEY (part_id) REFERENCES recycled_parts(id) ON DELETE SET NULL
);
CREATE TABLE recycled_device_submissions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    chat_id TEXT,
    user_id TEXT,
    message_id TEXT,
    lookup_kind TEXT NOT NULL,
    query_text TEXT,
    recognized_brand TEXT,
    recognized_model TEXT,
    matched_device_id INTEGER,
    matched_part_name TEXT,
    attachment_file_id TEXT,
    attachment_mime_type TEXT,
    provider_name TEXT,
    model_name TEXT,
    status TEXT NOT NULL DEFAULT 'queued',
    raw_payload_json TEXT,
    created_at TEXT NOT NULL, matched_part_number TEXT,
    FOREIGN KEY (matched_device_id) REFERENCES recycled_devices(id) ON DELETE SET NULL
);
CREATE TABLE telegram_user_sessions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    chat_id TEXT NOT NULL,
    user_id TEXT NOT NULL,
    session_type TEXT NOT NULL, 
    active_device_id INTEGER,
    status TEXT NOT NULL DEFAULT 'active', 
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL, active_device_name TEXT,
    UNIQUE(chat_id, user_id, session_type),
    FOREIGN KEY (active_device_id) REFERENCES recycled_devices(id) ON DELETE SET NULL
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_telegram_chat_messages_chat_key
  ON telegram_chat_messages(chat_key, id DESC);
CREATE INDEX idx_recycled_parts_device_id ON recycled_parts(device_id);
CREATE INDEX idx_recycled_devices_model ON recycled_devices(model);
CREATE INDEX idx_recycled_device_aliases_alias
    ON recycled_device_aliases(alias);
CREATE INDEX idx_recycled_part_aliases_alias
    ON recycled_part_aliases(alias);
CREATE INDEX idx_recycled_parts_part_name
    ON recycled_parts(part_name);
CREATE INDEX idx_recycled_device_submissions_status
    ON recycled_device_submissions(status, created_at DESC);
CREATE INDEX idx_telegram_user_sessions_user ON telegram_user_sessions(chat_id, user_id);
