INSERT INTO "telegram_chat_messages" ("id","chat_key","chat_id","user_id","role","intent","message_text","created_at") VALUES(2,'500100200:500100200','500100200','500100200','assistant','onboarding',replace('Rekomendowana ścieżka: API, adaptery i integracja danych.\nDla osob backendowych i integracyjnych, ktore chca pracowac nad schematami, OpenAPI, adapterami providerow i warstwa operacyjna. Ta sciezka pozostaje otwarta rowniez dla osob bez wlasnego sprzetu terenowego.\nPierwszy materiał: https://github.com/StrazPrzyszlosci/STRAZ_PRZYSZLOSCI/blob/main/docs/PRZYKLADY_GOTOWEGO_KODU.md\nDrugi materiał: https://github.com/StrazPrzyszlosci/STRAZ_PRZYSZLOSCI/blob/main/schemas/fish_pond_v1.yaml\nPierwsze zadania: issue:aq-09, issue:aq-13, issue:aq-26\nWarto też rozważyć później ścieżkę providera danych: https://github.com/StrazPrzyszlosci/STRAZ_PRZYSZLOSCI/blob/main/docs/JAK_ZOSTAC_DOSTAWCA_DANYCH.md','\n',char(10)),'2026-04-13T15:21:59.706Z');
