INSERT INTO "telegram_chat_messages" ("id","chat_key","chat_id","user_id","role","intent","message_text","created_at") VALUES(107,'8543582352:8543582352','8543582352','8543582352','user','chat','Czy moje części zostały dodane?','2026-04-15T21:21:03.993Z');
INSERT INTO "telegram_chat_messages" ("id","chat_key","chat_id","user_id","role","intent","message_text","created_at") VALUES(108,'8543582352:8543582352','8543582352','8543582352','assistant','chat',replace('Tak, Twoje zdjęcia części z HP EliteBook 2560p zostały dodane do kolejki. Możesz wysłać kolejne zdjęcia, jeśli chcesz udokumentować więcej elementów, lub wpisać `/stop` aby zakończyć przesyłanie.\n\nRozumiem, że interesuje Cię proces inwentaryzacji i baza danych części. Jak wspomniałem wcześniej, wykorzystujemy Ki-nTree w połączeniu z InvenTree do automatyzacji tego procesu. Możesz zapoznać się z dokumentacją dotyczącą Ki-nTree i InvenTree:\n\n*   [Ki-nTree GitHub](https://github.com/sparkmicro/Ki-nTree)\n*   [Dokumentacja InvenTree](https://docs.inventree.org/)\n\nJeśli chcesz się zaangażować w rozwój tego obszaru, możesz rozważyć rozwój modułu OCR, który automatycznie wyciąga symbole układów ze zdjęć i przekazuje je do API Ki-nTree. Szczegóły znajdziesz w dokumencie [Przykłady Gotowego Kodu i Otwartych Wzorców](https://github.com/StrazPrzyszlosci/STRAZ_PRZYSZLOSCI/blob/main/docs/PRZYKLADY_GOTOWEGO_KODU.md).\n\n**Następny krok:** Przejrzyj dokument [Przykłady Gotowego Kodu i Otwartych Wzorców](https://github.com/StrazPrzyszlosci/STRAZ_PRZYSZLOSCI/blob/main/docs/PRZYKLADY_GOTOWEGO_KODU.md) aby lepiej zrozumieć, jak działa integracja Ki-nTree i InvenTree.','\n',char(10)),'2026-04-15T21:21:03.993Z');
